+import { parseLogEvent, parseLogs } from './parse-logs'
+
+describe('parseLogs', () => {
+    it('parses agent_message with content (S3 stores full turns; chunks are filtered)', () => {
+        const line = JSON.stringify({
+            notification: {
+                method: 'session/update',
+                params: {
+                    update: {
+                        sessionUpdate: 'agent_message',
+                        content: { type: 'text', text: 'Here is the answer.' },
+                    },
+                },
+            },
+        })
+        const entries = parseLogs(line)
+        expect(entries).toHaveLength(1)
+        expect(entries[0].type).toBe('agent')
+        expect(entries[0].message).toBe('Here is the answer.')
+    })
+
+    it('parses agent_message using message field when content is absent', () => {
+        const line = JSON.stringify({
+            type: 'notification',
+            timestamp: '2026-01-01T00:00:00Z',
+            notification: {
+                method: 'session/update',
+                params: {
+                    update: {
+                        sessionUpdate: 'agent_message',
+                        message: 'Plain string reply',
+                    },
+                },
+            },
+        })
+        const entries = parseLogs(line)
+        expect(entries).toHaveLength(1)
+        expect(entries[0].type).toBe('agent')
+        expect(entries[0].message).toBe('Plain string reply')
+    })
+
+    it('merges consecutive agent_message lines', () => {
+        const log = [
+            JSON.stringify({
+                notification: {
+                    method: 'session/update',
+                    params: {
+                        update: {
+                            sessionUpdate: 'agent_message',
+                            content: { type: 'text', text: 'part-a' },
+                        },
+                    },
+                },
+            }),
+            JSON.stringify({
+                notification: {
+                    method: 'session/update',
+                    params: {
+                        update: {
+                            sessionUpdate: 'agent_message',
+                            content: { type: 'text', text: 'part-b' },
+                        },
+                    },
+                },
+            }),
+        ].join('\n')
+        const entries = parseLogs(log)
+        expect(entries).toHaveLength(1)
+        expect(entries[0].message).toBe('part-apart-b')
+    })
+})
+
+describe('parseLogEvent', () => {
+    it('parses agent_message from SSE-shaped objects', () => {
+        const event = {
+            type: 'notification',
+            timestamp: '2026-01-01T00:00:00Z',
+            notification: {
+                jsonrpc: '2.0',
+                method: 'session/update',
+                params: {
+                    update: {
+                        sessionUpdate: 'agent_message',
+                        content: { type: 'text', text: 'Streamed' },
+                    },
+                },
+            },
+        }
+        const toolMap = new Map()
+        const entry = parseLogEvent(event, 0, toolMap)
+        expect(entry?.type).toBe('agent')
+        expect(entry?.message).toBe('Streamed')
+    })
+})
