from __future__ import annotations

import logging
from collections import Counter
from dataclasses import dataclass
from typing import Any

import requests

from posthog.models.integration import GitHubIntegration, Integration

logger = logging.getLogger(__name__)

MAX_SUGGESTED_REVIEWERS = 3


@dataclass
class EnrichedReviewer:
    """A suggested reviewer, optionally linked to a PostHog user."""

    github_login: str
    user_id: int | None = None
    user_uuid: str | None = None
    first_name: str | None = None
    last_name: str | None = None
    email: str | None = None
    hedgehog_config: dict | None = None

    def to_dict(self) -> dict:
        return {
            "github_login": self.github_login,
            "user": {
                "id": self.user_id,
                "uuid": self.user_uuid,
                "first_name": self.first_name,
                "last_name": self.last_name,
                "email": self.email,
                "hedgehog_config": self.hedgehog_config,
            }
            if self.user_id is not None
            else None,
        }


def _get_github_integration(team_id: int) -> GitHubIntegration | None:
    """Get the first available GitHub integration for the team."""
    integration = Integration.objects.filter(team_id=team_id, kind="github").first()
    if integration is None:
        return None
    return GitHubIntegration(integration)


def _resolve_commit_author(github: GitHubIntegration, repo: str, sha: str) -> str | None:
    """Resolve a commit SHA to a GitHub login via the GitHub API."""
    if github.access_token_expired():
        try:
            github.refresh_access_token()
        except Exception:
            logger.warning("Failed to refresh GitHub token for commit resolution", exc_info=True)
            return None

    access_token = github.integration.sensitive_config.get("access_token")
    try:
        response = requests.get(
            f"https://api.github.com/repos/{repo}/commits/{sha}",
            headers={
                "Accept": "application/vnd.github+json",
                "Authorization": f"Bearer {access_token}",
                "X-GitHub-Api-Version": "2022-11-28",
            },
            timeout=10,
        )
        if response.status_code != 200:
            logger.info("GitHub API returned %d for commit %s in %s", response.status_code, sha[:8], repo)
            return None
        data = response.json()
        author = data.get("author")
        if author and author.get("login"):
            return author["login"]
    except Exception:
        logger.warning("Failed to resolve commit %s in %s", sha[:8], repo, exc_info=True)
    return None


def resolve_suggested_reviewers(
    team_id: int,
    repository: str,
    commit_hashes: list[str],
) -> list[str]:
    """Resolve commit hashes to up to 3 GitHub logins, ordered by relevance.

    Commits earlier in the list are weighted more heavily (they come from
    higher-priority findings and more critical code paths).
    """
    if not commit_hashes or not repository:
        return []

    github = _get_github_integration(team_id)
    if github is None:
        logger.info("No GitHub integration for team %d, cannot resolve reviewers", team_id)
        return []

    # Weight earlier commits more heavily (position-based weighting)
    login_weights: Counter[str] = Counter()
    seen_shas: set[str] = set()

    for i, sha in enumerate(commit_hashes):
        if sha in seen_shas:
            continue
        seen_shas.add(sha)

        login = _resolve_commit_author(github, repository, sha)
        if login:
            # Earlier commits get higher weight: first commit gets weight N, last gets 1
            weight = len(commit_hashes) - i
            login_weights[login] += weight

    # Return top reviewers by weighted score
    return [login for login, _ in login_weights.most_common(MAX_SUGGESTED_REVIEWERS)]


def enrich_reviewers_with_org_members(
    team_id: int,
    github_logins: list[str],
) -> list[EnrichedReviewer]:
    """Enrich GitHub logins with PostHog user info by matching via social auth.

    Returns EnrichedReviewer objects. When a GitHub login matches an org member
    who signed in with GitHub, the user info is populated; otherwise only
    github_login is set.
    """
    from social_django.models import UserSocialAuth

    from posthog.models.team.team import Team

    if not github_logins:
        return []

    try:
        org_id = Team.objects.values_list("organization_id", flat=True).get(id=team_id)
    except Team.DoesNotExist:
        return [EnrichedReviewer(github_login=login) for login in github_logins]

    # Fetch all GitHub social auth records for org members in one query
    social_auths = (
        UserSocialAuth.objects.filter(
            provider="github",
            user__organization_memberships__organization_id=org_id,
        )
        .select_related("user")
        .only(
            "extra_data",
            "user__id",
            "user__uuid",
            "user__first_name",
            "user__last_name",
            "user__email",
            "user__hedgehog_config",
        )
    )

    # Build login -> User mapping
    login_to_user: dict[str, Any] = {}
    for sa in social_auths:
        extra = sa.extra_data
        if isinstance(extra, dict):
            login = extra.get("login")
        else:
            continue
        if login:
            login_to_user[login.lower()] = sa.user

    enriched: list[EnrichedReviewer] = []
    for login in github_logins:
        user = login_to_user.get(login.lower())
        if user is not None:
            enriched.append(
                EnrichedReviewer(
                    github_login=login,
                    user_id=user.id,
                    user_uuid=str(user.uuid),
                    first_name=user.first_name,
                    last_name=user.last_name,
                    email=user.email,
                    hedgehog_config=user.hedgehog_config,
                )
            )
        else:
            enriched.append(EnrichedReviewer(github_login=login))

    return enriched


def get_github_login_for_user(user_id: int) -> str | None:
    """Get the GitHub login for a PostHog user via their social auth record."""
    from social_django.models import UserSocialAuth

    sa = UserSocialAuth.objects.filter(provider="github", user_id=user_id).first()
    if sa is None:
        return None
    extra = sa.extra_data
    if isinstance(extra, dict):
        return extra.get("login")
    return None

    search = self.request.query_params.get("search")
    if search:
        qs = qs.filter(Q(title__icontains=search) | Q(summary__icontains=search))

    # Annotate is_suggested_reviewer: True when the current user is among the cached reviewers.
    user_id = self.request.user.id
    qs = qs.annotate(
        is_suggested_reviewer=Case(
            When(suggested_reviewer_user_ids__contains=[user_id], then=Value(True)),
            default=Value(False),
            output_field=BooleanField(),
        )
    )

    return qs

def filter_queryset(self, queryset):
    """Ensure reports assigned to the current user always sort first."""
    qs = super().filter_queryset(queryset)
    # Prepend is_suggested_reviewer to whatever ordering DRF applied
    return qs.order_by("-is_suggested_reviewer", *qs.query.order_by)

def get_serializer_context(self):
    return {**super().get_serializer_context(), "team": self.team}

def destroy(self, request, *args, **kwargs):
    """Soft-delete a report and its signals via the deletion workflow."""
    report = cast(SignalReport, self.get_object())
    report_id = str(report.id)
    team_id = self.team.id

    try:
        client = sync_connect()
        async_to_sync(client.start_workflow)(  # type: ignore
            "signal-report-deletion",  # type: ignore
            SignalReportDeletionWorkflowInputs(team_id=team_id, report_id=report_id),  # type: ignore
            id=SignalReportDeletionWorkflow.workflow_id_for(team_id, report_id),
            task_queue=settings.VIDEO_EXPORT_TASK_QUEUE,
            execution_timeout=timedelta(minutes=30),
            retry_policy=RetryPolicy(maximum_attempts=1),
        )
    except WorkflowAlreadyStartedError:
        return Response({"status": "already_running", "report_id": report_id}, status=status.HTTP_200_OK)
    except Exception:
        logger.exception("Failed to start deletion workflow for report %s", report_id)
        return Response(
            {"error": "Failed to start deletion workflow."},
            status=status.HTTP_500_INTERNAL_SERVER_ERROR,
        )

    # Hide the report from the list immediately while signal deletion continues asynchronously.
    updated_fields = report.transition_to(SignalReport.Status.DELETED)
    report.save(update_fields=updated_fields)

    return Response({"status": "deletion_started", "report_id": report_id}, status=status.HTTP_202_ACCEPTED)

@extend_schema(exclude=True)
@action(detail=True, methods=["get"], url_path="artefacts", required_scopes=["task:read"])
def artefacts(self, request, pk=None, **kwargs):
    report = cast(SignalReport, self.get_object())

    )
}

function SuggestedReviewers({ reviewers }: { reviewers: EnrichedReviewer[] }): JSX.Element | null {
    if (reviewers.length === 0) {
        return null
    }

    return (
        <div className="border rounded bg-surface-primary mb-3 px-3 py-2 flex items-center gap-2">
            <span className="text-xs font-medium text-tertiary shrink-0">Suggested reviewers:</span>
            <div className="flex items-center gap-2 flex-wrap">
                {reviewers.map((reviewer) => (
                    <Link
                        key={reviewer.github_login}
                        to={`https://github.com/${reviewer.github_login}`}
                        target="_blank"
                        className="inline-flex items-center gap-1.5"
                    >
                        {reviewer.user ? (
                            <>
                                <ProfilePicture user={reviewer.user} size="xs" showName={false} />
                                <LemonTag size="small" type="highlight">
                                    {reviewer.user.first_name || `@${reviewer.github_login}`}
                                </LemonTag>
                            </>
                        ) : (
                            <LemonTag size="small" type="highlight">
                                @{reviewer.github_login}
                            </LemonTag>
                        )}
                    </Link>
                ))}
            </div>
        </div>
    )
}

function ReportDetailPane(): JSX.Element {
    const {
        selectedReport,
        shouldShowEnablingCtaOnMobile,
        artefacts,
        activeDetailTab,
        selectedReportSignals,
        reportSignalsLoading,
        selectedReportReviewers,
    } = useValues(inboxSceneLogic)
    const { deleteReport, reingestReport, setActiveDetailTab } = useActions(inboxSceneLogic)
    const { user } = useValues(userLogic)
    const { hasNoSources } = useValues(signalSourcesLogic)
    const { openSourcesModal } = useActions(signalSourcesLogic)

    const baseClasses = 'flex-1 p-4 min-w-0 h-full self-start bg-surface-primary flex flex-col overflow-y-auto'

    if (!selectedReport) {
        return (
            <div
                className={clsx(
                    baseClasses,

        )

    return Response({"status": "reingestion_started", "report_id": report_id}, status=status.HTTP_202_ACCEPTED)

@extend_schema(exclude=True)
@action(detail=True, methods=["get"], url_path="suggested_reviewers", required_scopes=["task:read"])
def suggested_reviewers(self, request, pk=None, **kwargs):
    """Resolve commit hashes from signal findings to GitHub logins, enriched with org member info."""
    report = cast(SignalReport, self.get_object())

    # Collect commit hashes from signal_finding artefacts (in order)
    finding_artefacts = report.artefacts.filter(type=SignalReportArtefact.ArtefactType.SIGNAL_FINDING).order_by(
        "created_at"
    )

    commit_hashes: list[str] = []
    for artefact in finding_artefacts:
        try:
            content = json.loads(artefact.content)
            for sha in content.get("relevant_commit_hashes", []):
                if sha and isinstance(sha, str):
                    commit_hashes.append(sha)
        except (json.JSONDecodeError, ValueError):
            continue

    # Get repository from repo_selection artefact
    repo_artefact = report.artefacts.filter(type=SignalReportArtefact.ArtefactType.REPO_SELECTION).first()
    repository = ""
    if repo_artefact:
        try:
            repo_content = json.loads(repo_artefact.content)
            repository = repo_content.get("repository", "") or ""
        except (json.JSONDecodeError, ValueError):
            pass

    if not commit_hashes or not repository:
        return Response({"results": []})

    github_logins = resolve_suggested_reviewers(self.team.id, repository, commit_hashes)
    enriched = enrich_reviewers_with_org_members(self.team.id, github_logins)

    # Cache resolved user IDs on the report for list-level sorting
    user_ids = [r.user_id for r in enriched if r.user_id is not None]
    report.suggested_reviewer_user_ids = user_ids or None
    report.save(update_fields=["suggested_reviewer_user_ids"])

