                            ),
                        },
                        {
                            key: 'signals',
                            label: `Signals graph`,
                            content: (
                                <div className="flex-1 overflow-hidden">
                                    {reportSignalsLoading && !selectedReportSignals ? (
                                        <div className="items-center justify-center h-full gap-2 text-sm text-tertiary">
                                            <Spinner className="size-4" />
